using InventoryFlow.Domain.Entities;
using MediatR;

namespace InventoryFlow.Application.Features.Products;

/// <summary>Supplies browser input for product creation.</summary>
public sealed record CreateProductRequest(string Name, string Sku);
/// <summary>Represents a product exposed to clients.</summary>
public sealed record ProductResponse(Guid Id, string Name, string Sku, DateTimeOffset CreatedAtUtc)
{
    /// <summary>Maps a domain product to a response.</summary>
    public static ProductResponse From(Product product) => new(product.Id, product.Name, product.Sku, product.CreatedAtUtc);
}
/// <summary>Creates a product in a server-resolved workspace.</summary>
public sealed record CreateProductCommand(Guid WorkspaceId, string Name, string Sku) : IRequest<ProductResponse>;
/// <summary>Lists active products in a server-resolved workspace.</summary>
public sealed record ListProductsQuery(Guid WorkspaceId) : IRequest<IReadOnlyList<ProductResponse>>;
/// <summary>Archives a product in a server-resolved workspace.</summary>
public sealed record ArchiveProductCommand(Guid WorkspaceId, Guid ProductId) : IRequest<bool>;
using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Products;

/// <summary>Provides workspace-scoped persistence operations for products.</summary>
public interface IProductCatalog
{
    /// <summary>Creates a product.</summary>
    Task<Product> CreateAsync(Product product, CancellationToken cancellationToken);
    /// <summary>Lists active products.</summary>
    Task<IReadOnlyList<Product>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken);
    /// <summary>Finds a product only within its workspace.</summary>
    Task<Product?> FindAsync(Guid workspaceId, Guid productId, CancellationToken cancellationToken);
    /// <summary>Persists pending changes.</summary>
    Task SaveChangesAsync(CancellationToken cancellationToken);
}

/// <summary>Represents a duplicate canonical SKU within a workspace.</summary>
public sealed class ProductSkuConflictException : Exception
{
    /// <summary>Initializes the exception.</summary>
    public ProductSkuConflictException() : base("A product with this SKU already exists in the workspace.") { }
}
using InventoryFlow.Domain.Entities;
using MediatR;

namespace InventoryFlow.Application.Features.Products;

/// <summary>Handles product creation.</summary>
public sealed class CreateProductHandler(IProductCatalog catalog, TimeProvider timeProvider) : IRequestHandler<CreateProductCommand, ProductResponse>
{
    /// <inheritdoc />
    public async Task<ProductResponse> Handle(CreateProductCommand request, CancellationToken cancellationToken)
    {
        var product = new Product(Guid.NewGuid(), request.WorkspaceId, request.Name, request.Sku, timeProvider.GetUtcNow());
        return ProductResponse.From(await catalog.CreateAsync(product, cancellationToken));
    }
}
/// <summary>Handles active-product listing.</summary>
public sealed class ListProductsHandler(IProductCatalog catalog) : IRequestHandler<ListProductsQuery, IReadOnlyList<ProductResponse>>
{
    /// <inheritdoc />
    public async Task<IReadOnlyList<ProductResponse>> Handle(ListProductsQuery request, CancellationToken cancellationToken) =>
        (await catalog.ListActiveAsync(request.WorkspaceId, cancellationToken)).Select(ProductResponse.From).ToArray();
}
/// <summary>Handles idempotent product archive.</summary>
public sealed class ArchiveProductHandler(IProductCatalog catalog, TimeProvider timeProvider) : IRequestHandler<ArchiveProductCommand, bool>
{
    /// <inheritdoc />
    public async Task<bool> Handle(ArchiveProductCommand request, CancellationToken cancellationToken)
    {
        var product = await catalog.FindAsync(request.WorkspaceId, request.ProductId, cancellationToken);
        if (product is null) return false;
        product.Archive(timeProvider.GetUtcNow());
        await catalog.SaveChangesAsync(cancellationToken);
        return true;
    }
}
using FluentValidation;
using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Products;

/// <summary>Validates product creation input.</summary>
public sealed class CreateProductCommandValidator : AbstractValidator<CreateProductCommand>
{
    /// <summary>Initializes validation rules.</summary>
    public CreateProductCommandValidator()
    {
        RuleFor(command => command.WorkspaceId).NotEmpty();
        RuleFor(command => command.Name).NotEmpty().MaximumLength(Product.NameMaxLength);
        RuleFor(command => command.Sku).NotEmpty().MaximumLength(Product.SkuMaxLength);
    }
}
using InventoryFlow.Application.Features.Products;
using InventoryFlow.Domain.Entities;
using InventoryFlow.Infrastructure.Persistence;
using Microsoft.Data.SqlClient;
using Microsoft.EntityFrameworkCore;

namespace InventoryFlow.Infrastructure.Products;

/// <summary>Persists workspace-scoped products with SQL Server uniqueness handling.</summary>
public sealed class EfProductCatalog(ApplicationDbContext dbContext) : IProductCatalog
{
    /// <inheritdoc />
    public async Task<Product> CreateAsync(Product product, CancellationToken cancellationToken)
    {
        dbContext.Products.Add(product);
        try
        {
            await dbContext.SaveChangesAsync(cancellationToken);
            return product;
        }
        catch (DbUpdateException exception) when (exception.InnerException is SqlException { Number: 2601 or 2627 })
        {
            throw new ProductSkuConflictException();
        }
    }

    /// <inheritdoc />
    public async Task<IReadOnlyList<Product>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken) =>
        await dbContext.Products.AsNoTracking().Where(item => item.WorkspaceId == workspaceId && item.ArchivedAtUtc == null)
            .OrderBy(item => item.Name).ThenBy(item => item.Id).ToListAsync(cancellationToken);

    /// <inheritdoc />
    public Task<Product?> FindAsync(Guid workspaceId, Guid productId, CancellationToken cancellationToken) =>
        dbContext.Products.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId && item.Id == productId, cancellationToken);

    /// <inheritdoc />
    public async Task SaveChangesAsync(CancellationToken cancellationToken) => await dbContext.SaveChangesAsync(cancellationToken);
}

